module top_module(
    input [3:0] A,
    input [3:0] B,
    output [3:0] max_out
);wire [3:0] min_val;

    // Compare each bit and store the maximum value in min_val
    assign min_val[0] = (A[0] > B[0]) ? A[0] : B[0];
    assign min_val[1] = (A[1] > B[1]) ? A[1] : B[1];
    assign min_val[2] = (A[2] > B[2]) ? A[2] : B[2];
    assign min_val[3] = (A[3] > B[3]) ? A[3] : B[3];

    // Assign the temporary maximum value to the output
    assign max_out = min_val;

endmodule
